// ── Helpers ───────────────────────────────────────────────────────────────
const fmtNum = (v, d = 2) => {
  if (v == null || isNaN(v)) return '--';
  return Number(v).toFixed(d);
};

const fmtPct = (v) => {
  if (v == null || isNaN(v)) return '--';
  return `${Number(v).toFixed(1)}%`;
};

const rankColor = (idx) => {
  if (idx === 0) return T.gold;
  if (idx === 1) return T.silver;
  if (idx === 2) return T.bronze;
  return T.textSec;
};

// ── Rental tier computation (mirrors backend RENTAL_PRICING) ─────────────
const RENTAL_TIERS = {
  elite:    { min: 50, price: 49.99, label: 'Elite',    color: '#D29922' },
  strong:   { min: 25, price: 29.99, label: 'Strong',   color: '#3FB950' },
  solid:    { min: 10, price: 19.99, label: 'Solid',    color: '#58A6FF' },
  emerging: { min: 0,  price: 9.99,  label: 'Emerging', color: '#8B949E' },
};

function getRentalInfo(avgReturn) {
  // avgReturn is the raw value from the API — normalize to pct then annualize
  const retPct = Math.abs(avgReturn) > 1 ? avgReturn : avgReturn * 100;
  const annual = retPct * 252;
  if (annual >= 50) return { ...RENTAL_TIERS.elite, annual };
  if (annual >= 25) return { ...RENTAL_TIERS.strong, annual };
  if (annual >= 10) return { ...RENTAL_TIERS.solid, annual };
  return { ...RENTAL_TIERS.emerging, annual };
}

