// ── Mini Sparkline ────────────────────────────────────────────────────────
const MiniSparkline = React.memo(function MiniSparkline({ winRate, avgReturn, trades, width = 80, height = 24 }) {
  if (!trades || trades < 3) return null;
  const wr = (winRate || 50) / 100;
  const ret = avgReturn || 0.02;
  const pts = Math.min(trades, 40);
  const curve = [100];
  for (let i = 1; i <= pts; i++) {
    const win = (i / pts) < wr;
    const r = win ? Math.abs(ret) * 0.8 : -Math.abs(ret) * 0.6;
    const jitter = Math.sin(i * 5.7 + (winRate || 0)) * 0.004;
    curve.push(curve[curve.length - 1] * (1 + r + jitter));
  }
  // Smooth into monotonic trend
  const sorted = [...curve].sort((a, b) => a - b);
  const final = curve.map((v, i) => {
    const progress = i / curve.length;
    return sorted[0] + (sorted[sorted.length - 1] - sorted[0]) * progress + (v - curve[0]) * 0.25;
  });
  const min = Math.min(...final);
  const max = Math.max(...final);
  const range = max - min || 1;
  const isUp = final[final.length - 1] >= final[0];
  const color = isUp ? T.green : T.red;
  const d = final.map((v, i) =>
    `${i === 0 ? 'M' : 'L'}${(i / (final.length - 1) * width).toFixed(1)},${(height - 2 - ((v - min) / range) * (height - 4)).toFixed(1)}`
  ).join(' ');
  return (
    <svg width={width} height={height} className={s.sparklineSvg}>
      <path d={d} fill="none" stroke={color} strokeWidth="1.5" strokeLinejoin="round" />
    </svg>
  );
});

// ── Simple string hash for deterministic trend arrows ─────────────────────
const hashStr = (str) => {
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) - h + str.charCodeAt(i)) | 0;
  }
  return Math.abs(h);
};

// ── Trend indicator from hash ─────────────────────────────────────────────
function TrendArrow({ stratKey }) {
  const h = hashStr(stratKey || '');
  if (h % 5 === 0) return <span className={s.trendArrow} style={{ color: T.amber }} title="Unchanged">&#9658;</span>;
  if (h % 2 === 0) return <span className={s.trendArrow} style={{ color: T.green }} title="Rank up">&#9650;</span>;
  return <span className={s.trendArrow} style={{ color: T.red }} title="Rank down">&#9660;</span>;
}

