// TRADERS LEADERBOARD (sub-component for "Traders" tab)
// ═══════════════════════════════════════════════════════════════════════════
function TradersLeaderboard() {
  const [rankings, setRankings] = useState([]);
  const [myRank, setMyRank] = useState(null);
  const [loading, setLoading] = useState(true);
  const [timeframe, setTimeframe] = useState('all');
  const [badges, setBadges] = useState({});
  const [achievements, setAchievements] = useState(null);

  useEffect(() => {
    (async () => {
      setLoading(true);
      try {
        // Primary: user-rankings/global endpoint
        let data;
        try {
          data = await api(`/user-rankings/global?timeframe=${timeframe}&limit=100`);
        } catch {
          // Fallback to old endpoint
          try {
            data = await api(`/rankings/global?timeframe=${timeframe}&limit=100`);
          } catch {}
        }
        setRankings(data?.rankings || data?.leaderboard || []);
      } catch {}
      setLoading(false);
    })();
  }, [timeframe]);

  // Fetch my ranking
  useEffect(() => {
    api('/user-rankings/me', { silent: true })
      .then(d => setMyRank(d?.rank || d || null))
      .catch(() => {});
  }, []);

  // Fetch achievement badges
  useEffect(() => {
    Promise.all([
      api('/rewards/leaderboard-badges', { silent: true }).catch(() => ({})),
      api('/achievements/summary', { silent: true }).catch(() => null),
    ]).then(([badgeData, achData]) => {
      setBadges(badgeData?.badges || {});
      setAchievements(achData);
    });
  }, []);

  const avatarColor = (name) => {
    let hash = 0;
    for (let i = 0; i < (name || '').length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
    const colors = ['#58A6FF', '#3FB950', '#D29922', '#BC8CFF', '#F85149', '#F0883E', '#56D4DD'];
    return colors[Math.abs(hash) % colors.length];
  };

  return (
    <div>
      {/* My Rank card */}
      {myRank && (
        <div style={{
          display: 'flex', alignItems: 'center', gap: 16, padding: '12px 18px', marginBottom: 16,
          background: '#58A6FF08', border: '1px solid #58A6FF22', borderRadius: 10,
        }}>
          <div style={{
            width: 40, height: 40, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center',
            background: '#58A6FF18', color: '#58A6FF', fontWeight: 800, fontSize: 16,
            fontFamily: T.mono,
          }}>
            #{myRank.rank || myRank.position || '--'}
          </div>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 13, fontWeight: 600, color: T.text }}>Your Ranking</div>
            <div style={{ fontSize: 11, color: T.textSec }}>
              {myRank.total_return != null || myRank.cumulative_pnl_pct != null
                ? `Return: ${((myRank.total_return || myRank.cumulative_pnl_pct || 0) > 0 ? '+' : '')}${(myRank.total_return || myRank.cumulative_pnl_pct || 0).toFixed(1)}%`
                : ''}
              {myRank.win_rate != null ? ` | Win Rate: ${(myRank.win_rate || 0).toFixed(0)}%` : ''}
              {myRank.total_trades != null ? ` | Trades: ${myRank.total_trades}` : ''}
            </div>
          </div>
          {achievements && (
            <div style={{ display: 'flex', gap: 6 }}>
              {(achievements.badges || achievements.recent || []).slice(0, 3).map((b, i) => (
                <span key={i} style={{
                  fontSize: 10, fontWeight: 700, padding: '2px 8px', borderRadius: 8,
                  background: '#D2992218', color: '#D29922',
                }} title={b.description || b.name}>
                  {b.icon || b.emoji || ''} {b.name || b.label || ''}
                </span>
              ))}
              {achievements.total_count > 0 && (
                <span style={{ fontSize: 10, color: T.textSec, alignSelf: 'center' }}>
                  {achievements.total_count} total
                </span>
              )}
            </div>
          )}
        </div>
      )}

      <div className={s.controls} style={{ marginBottom: 16 }}>
        {['1w', '1m', '3m', 'all'].map(tf => (
          <button
            key={tf}
            className={timeframe === tf ? s.filterBtnActive : s.filterBtn}
            onClick={() => setTimeframe(tf)}
          >
            {tf.toUpperCase()}
          </button>
        ))}
      </div>

      {loading ? (
        <div>{[1,2,3,4,5].map(i => <div key={i} className={s.skeletonRow} />)}</div>
      ) : rankings.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '40px', color: '#8B949E' }}>
          No rankings yet. Check back after the first ranking update.
        </div>
      ) : (
        <GlassPanel className={s.tableWrap}>
          <div className={s.tableHeader} style={{ gridTemplateColumns: '50px 1fr 100px 80px 80px 60px' }}>
            <span className={s.tableHeaderCell}>#</span>
            <span className={s.tableHeaderCell}>Trader</span>
            <span className={s.tableHeaderCell} style={{ textAlign: 'right' }}>Return</span>
            <span className={s.tableHeaderCell} style={{ textAlign: 'right' }}>Win Rate</span>
            <span className={s.tableHeaderCell} style={{ textAlign: 'right' }}>Trades</span>
            <span className={s.tableHeaderCell} style={{ textAlign: 'right' }}>Move</span>
          </div>
          {rankings.map((r, i) => (
            <div key={r.user_id || i} className={s.tableRow} style={{ gridTemplateColumns: '50px 1fr 100px 80px 80px 60px' }}>
              <span className={i === 0 ? s.rankGold : i === 1 ? s.rankSilver : i === 2 ? s.rankBronze : s.rankBadge}>
                {r.rank || i + 1}
              </span>
              <span style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <span style={{
                  width: 28, height: 28, borderRadius: '50%', display: 'flex',
                  alignItems: 'center', justifyContent: 'center', fontSize: 12, fontWeight: 700,
                  background: avatarColor(r.display_name || r.username) + '22',
                  color: avatarColor(r.display_name || r.username),
                }}>
                  {(r.display_name || r.username || '?')[0].toUpperCase()}
                </span>
                <span>{r.display_name || r.username}</span>
                {badges[r.user_id] && (
                  <span style={{
                    fontSize: 10, fontWeight: 700, padding: '1px 6px', borderRadius: 8, marginLeft: 6,
                    background: ({ gold: '#D2992222', silver: '#8B949E22', bronze: '#CD7F3222' })[badges[r.user_id]],
                    color: ({ gold: '#D29922', silver: '#8B949E', bronze: '#CD7F32' })[badges[r.user_id]],
                  }}>
                    {badges[r.user_id].toUpperCase()}
                  </span>
                )}
              </span>
              <span className={s.metricCell}>
                <span className={s.metricValue} style={{ color: r.cumulative_pnl_pct > 0 ? '#3FB950' : r.cumulative_pnl_pct < 0 ? '#F85149' : '#8B949E' }}>
                  {r.cumulative_pnl_pct > 0 ? '+' : ''}{(r.cumulative_pnl_pct || 0).toFixed(1)}%
                </span>
              </span>
              <span className={s.metricCell}>
                <span className={s.metricValue}>{(r.win_rate || 0).toFixed(0)}%</span>
              </span>
              <span className={s.metricCell}>
                <span className={s.tradesValue}>{r.total_trades || 0}</span>
              </span>
              <span className={s.metricCell}>
                <span className={s.metricValue} style={{
                  fontWeight: 600,
                  color: r.delta > 0 ? '#3FB950' : r.delta < 0 ? '#F85149' : '#484F58',
                }}>
                  {r.delta > 0 ? `+${r.delta}` : r.delta < 0 ? `${r.delta}` : '-'}
                </span>
              </span>
            </div>
          ))}
        </GlassPanel>
      )}
    </div>
  );
}

