// MAIN COMPONENT
// ═══════════════════════════════════════════════════════════════════════════
export default function LeaderboardPage() {
  usePageTitle('Alpha Leaderboard');
  const navigate = useNavigate();

  const [strategies, setStrategies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState('strategies');

  // Filters
  const [sortBy, setSortBy] = useState('sharpe');
  const [sideFilter, setSideFilter] = useState('all');
  const [period, setPeriod] = useState('all');
  const [bannerDismissed, setBannerDismissed] = useState(() => !!localStorage.getItem('aura_leaderboard_banner_dismissed'));
  const [showShare, setShowShare] = useState(false);
  const [myCard, setMyCard] = useState(null);
  const { tier: userTier } = usePlatformFeatures();
  const [foundingSpots, setFoundingSpots] = useState(null);

  // Tournament state
  const [tournaments, setTournaments] = useState([]);

  // ── Fetch data ────────────────────────────────────────────────────────
  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      // Map side filter: 'crypto' maps to asset_class=crypto + direction=all
      const isCrypto = sideFilter === 'crypto';
      const assetClass = isCrypto ? 'crypto' : 'us';
      const direction = isCrypto ? 'all' : sideFilter;

      // Map period to backend timeframe format
      const timeframeMap = { '1m': '1m', '3m': '3m', '6m': '6m', '1y': '1y', 'all': 'all' };
      const timeframe = timeframeMap[period] || 'all';

      // Try multiple endpoints in priority order
      let data = null;

      // 1. Primary: v2 strategy leaderboard
      try {
        data = await api(
          `/v2/data/strategies/leaderboard?sort_by=${sortBy}&direction=${direction}&asset_class=${assetClass}&timeframe=${timeframe}&limit=100`
        );
      } catch {}

      // 2. Fallback: legacy leaderboards endpoint
      if (!data) {
        try {
          data = await api(
            `/leaderboards/strategies?sort_by=${sortBy}&direction=${direction}&asset_class=${assetClass}&timeframe=${timeframe}&limit=100`
          );
        } catch {}
      }

      // 3. Fallback: strategies catalogue
      if (!data) {
        try {
          data = await api(`/strategies?limit=100`);
          if (data?.strategies) {
            data = { leaderboard: data.strategies };
          }
        } catch {}
      }

      // 4. Last resort: aura_alpha winners
      if (!data) {
        try {
          const winners = await api('/aura_alpha/winners');
          if (winners?.winners || winners?.strategies) {
            data = { leaderboard: winners.winners || winners.strategies };
          }
        } catch {}
      }

      if (data?.leaderboard) {
        setStrategies(data.leaderboard);
      } else if (data?.strategies) {
        setStrategies(data.strategies);
      } else if (Array.isArray(data)) {
        setStrategies(data);
      } else {
        setStrategies([]);
      }
    } catch (err) {
      setError('Failed to load leaderboard data');
      setStrategies([]);
    }
    setLoading(false);
  }, [sortBy, sideFilter, period]);

  useEffect(() => { fetchData(); }, [fetchData]);

  // Fetch tournaments
  useEffect(() => {
    api('/tournaments', { silent: true })
      .then(d => setTournaments(d?.tournaments || d || []))
      .catch(() => {});
  }, []);

  // Fetch founding spots for upgrade banner (free users only)
  useEffect(() => {
    if (userTier && userTier !== 'explorer' && userTier !== 'free') return;
    api('/auth/founding-spots', { silent: true }).then(setFoundingSpots).catch(() => {});
  }, [userTier]);

  // ── Computed stats ──────────────────────────────────────────────────────
  const stats = useMemo(() => {
    if (strategies.length === 0) {
      return { total: 0, avgSharpe: '--', topWinRate: '--', bestReturn: '--' };
    }
    const sharpes = strategies.map(st => st.sharpe || 0).filter(v => v !== 0);
    const avgSharpe = sharpes.length > 0 ? (sharpes.reduce((a, b) => a + b, 0) / sharpes.length).toFixed(2) : '--';
    const topWinRate = Math.max(...strategies.map(st => st.win_rate || 0));
    const bestReturn = Math.max(...strategies.map(st => {
      const ret = st.avg_return || 0;
      return ret > 1 ? ret : ret * 100; // normalize to percentage
    }));

    return {
      total: strategies.length,
      avgSharpe,
      topWinRate: topWinRate > 0 ? fmtPct(topWinRate) : '--',
      bestReturn: bestReturn > 0 ? fmtPct(bestReturn) : '--',
    };
  }, [strategies]);

  // ── Table column headers ──────────────────────────────────────────────
  const columns = [
    { key: 'rank', label: '#', align: 'center' },
    { key: 'name', label: 'Strategy', align: 'left' },
    { key: 'equity', label: 'Equity', align: 'center' },
    { key: 'side', label: 'Side', align: 'center' },
    { key: 'sharpe', label: 'Sharpe', align: 'right' },
    { key: 'win_rate', label: 'Win Rate', align: 'right' },
    { key: 'avg_return', label: 'Return', align: 'right' },
    { key: 'profit_factor', label: 'PF', align: 'right' },
    { key: 'max_drawdown', label: 'Max DD', align: 'right' },
    { key: 'trades', label: 'Trades', align: 'right' },
    { key: 'rental', label: 'Rent', align: 'right' },
    { key: 'status', label: 'Status', align: 'center' },
    { key: 'actions', label: '', align: 'center' },
  ];

  if (loading && activeTab === 'strategies') {
    return (
      <div className={s.page}>
        <style>{`@keyframes skeletonPulse { 0%, 100% { opacity: 0.3; } 50% { opacity: 0.7; } }`}</style>
        <h1 className={s.headerTitle}>Alpha Leaderboard</h1>
        <p className={s.headerSubLoading}>
          Top performing strategies ranked by risk-adjusted returns
        </p>
        {/* Tab bar even in loading state */}
        <div className={s.tabs}>
          <button className={`${s.tab} ${s.tabActive}`}>Strategies</button>
          <button className={s.tab} onClick={() => setActiveTab('traders')}>Traders</button>
        </div>
        {/* Skeleton: summary stat cards */}
        <SkeletonMetricRow count={4} />
        {/* Skeleton: filter bar placeholder */}
        <div style={{ margin: '20px 0 16px', display: 'flex', gap: 12, alignItems: 'center' }}>
          {[80, 65, 55, 70, 50, 75].map((w, i) => (
            <div key={i} style={{
              width: w, height: 28, borderRadius: 6,
              background: '#111A24', animation: 'skeletonPulse 1.5s ease-in-out infinite',
              animationDelay: `${i * 0.06}s`,
            }} />
          ))}
        </div>
        {/* Skeleton: leaderboard table rows */}
        <GlassPanel className={s.tableWrap}>
          <div className={s.tableHeader}>
            {columns.map(col => (
              <span key={col.key} className={s.tableHeaderCell} style={{ textAlign: col.align }}>
                {col.label}
              </span>
            ))}
          </div>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <tbody>
              {Array.from({ length: 10 }).map((_, r) => (
                <SkeletonRow key={r} cols={columns.length} />
              ))}
            </tbody>
          </table>
        </GlassPanel>
      </div>
    );
  }

  return (
    <div className={s.page}>
      {/* ── Header ──────────────────────────────────────────────────── */}
      <div className={s.header}>
        <h1 className={s.headerTitle}>Alpha Leaderboard</h1>
        <p className={s.headerSub}>
          Top performing strategies ranked by risk-adjusted returns
        </p>
      </div>

      {/* ── Tab Bar ──────────────────────────────────────────────────── */}
      <div className={s.tabs} style={{ display: 'flex', alignItems: 'center', gap: 0 }}>
        <button
          className={`${s.tab} ${activeTab === 'strategies' ? s.tabActive : ''}`}
          onClick={() => setActiveTab('strategies')}
        >
          Strategies
        </button>
        <button
          className={`${s.tab} ${activeTab === 'traders' ? s.tabActive : ''}`}
          onClick={() => setActiveTab('traders')}
        >
          Traders
        </button>
        <div style={{ flex: 1 }} />
        <button onClick={async () => {
          const c = await api('/growth/card', { silent: true }).catch(() => null);
          if (c) { setMyCard(c); setShowShare(true); }
        }} style={{ padding: '6px 14px', background: '#58A6FF11', border: '1px solid #58A6FF44', borderRadius: 8, color: '#58A6FF', fontSize: 12, fontWeight: 600, cursor: 'pointer' }}>
          Share My Rank
        </button>
      </div>

      {/* ── Founding Spots Banner (free users only) ──────────────────── */}
      {(userTier === 'explorer' || userTier === 'free' || !userTier) && foundingSpots?.remaining > 0 && (
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 16px', background: '#D2992211', border: '1px solid #D2992244', borderRadius: 8, marginBottom: 16, fontSize: 13 }}>
          <span style={{ color: '#D29922' }}>
            <strong>{foundingSpots.remaining}</strong> founding spots remaining — lifetime access at launch pricing
          </span>
          <button onClick={() => navigate('/billing')} style={{ padding: '6px 16px', background: '#D29922', border: 'none', borderRadius: 6, color: '#0D1117', fontWeight: 600, fontSize: 12, cursor: 'pointer', flexShrink: 0, marginLeft: 12 }}>
            Claim Spot
          </button>
        </div>
      )}

      {/* ── Traders Tab Content ──────────────────────────────────────── */}
      {activeTab === 'traders' && <TradersLeaderboard />}

      {/* ── Strategies Tab Content ───────────────────────────────────── */}
      {activeTab === 'strategies' && <>

      {/* ── Summary Stats ───────────────────────────────────────────── */}
      <div className={s.statsGrid}>
        <StatCard label="Total Strategies" value={stats.total} color={T.blue} />
        <StatCard label="Avg Sharpe Ratio" value={stats.avgSharpe} color={T.purple} />
        <StatCard label="Top Win Rate" value={stats.topWinRate} color={T.green} />
        <StatCard label="Best Return" value={stats.bestReturn} color={T.amber} />
      </div>

      {/* ── Filter / Sort Bar ───────────────────────────────────────── */}
      <GlassPanel className={s.controlsPanel}>
        <div className={s.controls}>
          {/* Sort dropdown */}
          <label className={s.controlLabel}>
            Sort by
            <select value={sortBy} onChange={e => setSortBy(e.target.value)} className={s.sortSelect}>
              {SORT_OPTIONS.map(opt => (
                <option key={opt.key} value={opt.key}>{opt.label}</option>
              ))}
            </select>
          </label>

          {/* Divider */}
          <div className={s.divider} />

          {/* Side filter pills */}
          <div className={s.filterGroup}>
            <span className={s.filterGroupLabel}>Side</span>
            {SIDE_OPTIONS.map(opt => (
              <FilterPill
                key={opt.key}
                label={opt.label}
                active={sideFilter === opt.key}
                onClick={() => setSideFilter(opt.key)}
              />
            ))}
          </div>

          {/* Divider */}
          <div className={s.divider} />

          {/* Period filter pills */}
          <div className={s.filterGroup}>
            <span className={s.filterGroupLabel}>Period</span>
            {PERIOD_OPTIONS.map(opt => (
              <FilterPill
                key={opt.key}
                label={opt.label}
                active={period === opt.key}
                onClick={() => setPeriod(opt.key)}
              />
            ))}
          </div>

          {/* Result count */}
          <span className={s.resultCount}>
            {strategies.length} results
          </span>
        </div>
      </GlassPanel>

      {/* ── Error State ─────────────────────────────────────────────── */}
      {error && (
        <GlassPanel className={s.errorPanel}>
          <div className={s.errorMsg}>{error}</div>
        </GlassPanel>
      )}

      {/* ── New User Guidance Banner ──────────────────────────────── */}
      {!bannerDismissed && (() => {
        try {
          const reg = localStorage.getItem('aura_registered_at');
          const daysSinceReg = reg ? (Date.now() - new Date(reg).getTime()) / 86400000 : 0;
          if (!reg || daysSinceReg <= 7) {
            return (
              <div className={s.banner}>
                <span className={s.bannerText}>
                  New here? Pick a strategy below and click "Subscribe" to see its full backtest results.
                </span>
                <div className={s.bannerActions}>
                  <Link to="/gateway" className={s.bannerLink}>
                    Connect Broker First &rarr;
                  </Link>
                  <button
                    onClick={() => { localStorage.setItem('aura_leaderboard_banner_dismissed', '1'); setBannerDismissed(true); }}
                    className={s.bannerDismiss}
                  >
                    &times;
                  </button>
                </div>
              </div>
            );
          }
        } catch {}
        return null;
      })()}

      {/* ── Leaderboard Table ───────────────────────────────────────── */}
      <GlassPanel className={s.tableWrap}>
        {/* Table header */}
        <div className={s.tableHeader}>
          {columns.map(col => (
            <span key={col.key} className={s.tableHeaderCell} style={{ textAlign: col.align }}>
              {col.label}
            </span>
          ))}
        </div>

        {/* Table rows */}
        {strategies.map((strat, idx) => {
          const sharpe = strat.sharpe ?? 0;
          const winRate = strat.win_rate ?? 0;
          const avgReturn = strat.avg_return ?? 0;
          const pf = strat.profit_factor ?? 0;
          const maxDD = strat.max_drawdown ?? 0;
          const trades = strat.total_trades ?? 0;
          const name = strat.strategy_name ?? strat.name ?? strat.label ?? strat.strategy_key ?? '--';
          const direction = strat.direction ?? '--';
          const category = strat.category ?? '';
          const stratKey = strat.strategy_key ?? strat.key ?? name;

          // Determine status
          let status = 'BACKTEST';
          if (strat.status === 'active') status = 'LIVE';
          else if (strat.status === 'paper') status = 'PAPER';

          // Color coding (dynamic — kept inline)
          const sharpeColor = sharpe >= 1.5 ? T.green : sharpe >= 1.0 ? T.amber : sharpe > 0 ? T.text : T.red;
          const wrColor = winRate >= 60 ? T.green : winRate >= 50 ? T.text : T.red;
          const returnVal = avgReturn > 1 ? avgReturn : avgReturn * 100;
          const returnColor = returnVal > 0 ? T.green : returnVal < 0 ? T.red : T.text;
          const pfColor = pf >= 2.0 ? T.green : pf >= 1.3 ? T.amber : pf > 0 ? T.text : T.red;
          const ddColor = maxDD > 20 ? T.red : maxDD > 10 ? T.amber : T.text;

          // Rank class
          const rankCls = idx === 0 ? s.rankGold : idx === 1 ? s.rankSilver : idx === 2 ? s.rankBronze : s.rankBadge;

          return (
            <div
              key={stratKey + idx}
              className={s.tableRow}
              onClick={() => navigate(`/strategies/${encodeURIComponent(stratKey)}`)}
            >
              {/* Rank + Trend */}
              <div className={s.rankCell}>
                <span className={rankCls}>
                  {idx + 1}
                </span>
                <TrendArrow stratKey={stratKey} />
              </div>

              {/* Strategy Name + Category Dot + Hot Badge */}
              <div className={s.strategyName}>
                <div className={s.strategyNameInner}>
                  <CategoryDot category={category} />
                  <span className={s.strategyNameText}>{name}</span>
                  {trades > 1000 && winRate > 55 && <HotBadge />}
                </div>
                {category && (
                  <div className={s.strategyCategoryLabel}>
                    {category}
                  </div>
                )}
              </div>

              {/* Equity Sparkline */}
              <div className={s.sparklineCell}>
                <MiniSparkline winRate={winRate} avgReturn={avgReturn} trades={trades} />
              </div>

              {/* Side */}
              <div className={s.centerCell}>
                <SidePill direction={category === 'crypto' ? 'crypto' : direction} />
              </div>

              {/* Sharpe */}
              <div className={s.metricCell}>
                <span className={s.metricValue} style={{ color: sharpeColor }}>
                  {fmtNum(sharpe)}
                </span>
              </div>

              {/* Win Rate */}
              <div className={s.metricCell}>
                <span className={s.metricValue} style={{ color: wrColor }}>
                  {fmtPct(winRate)}
                </span>
              </div>

              {/* Return */}
              <div className={s.metricCell}>
                <span className={s.metricValue} style={{ color: returnColor }}>
                  {returnVal > 0 ? '+' : ''}{fmtPct(returnVal)}
                </span>
              </div>

              {/* Profit Factor */}
              <div className={s.metricCell}>
                <span className={s.metricValue} style={{ color: pfColor }}>
                  {fmtNum(pf)}
                </span>
              </div>

              {/* Max Drawdown */}
              <div className={s.metricCell}>
                <span className={s.metricValue} style={{ color: ddColor }}>
                  {maxDD > 0 ? `-${fmtPct(maxDD)}` : '--'}
                </span>
              </div>

              {/* Trades */}
              <div className={s.metricCell}>
                <span className={s.tradesValue}>
                  {trades > 0 ? trades.toLocaleString() : '--'}
                </span>
              </div>

              {/* Rental Price */}
              {(() => {
                const rental = getRentalInfo(avgReturn);
                return (
                  <div className={s.metricCell}>
                    <span
                      style={{
                        fontFamily: T.mono, fontSize: 12, fontWeight: 700,
                        color: rental.color,
                        cursor: 'pointer',
                      }}
                      title={`${rental.label} tier - $${rental.price}/mo`}
                      onClick={(e) => {
                        e.stopPropagation();
                        navigate(`/strategies/${encodeURIComponent(stratKey)}`);
                      }}
                    >
                      ${rental.price}
                    </span>
                  </div>
                );
              })()}

              {/* Status */}
              <div className={s.centerCell}>
                <StatusPill status={status} />
              </div>

              {/* Actions */}
              <div className={s.actionsCell} onClick={(e) => e.stopPropagation()}>
                <ActionButton label="Subscribe" colorKey="blue" onClick={() => navigate(`/strategies/${encodeURIComponent(stratKey)}`)} />
                <ActionButton label="Copy" colorKey="green" onClick={() => navigate('/copy-trading')} />
                <ActionButton label="Rent" colorKey="purple" onClick={() => navigate(`/strategies/${encodeURIComponent(stratKey)}`)} />
              </div>
            </div>
          );
        })}

        {/* Empty state */}
        {strategies.length === 0 && !loading && (
          <div className={s.emptyState}>
            <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke={T.textSec} strokeWidth="1.5" className={s.emptyIcon}>
              <path d="M12 2L2 7l10 5 10-5-10-5z" />
              <path d="M2 17l10 5 10-5" />
              <path d="M2 12l10 5 10-5" />
            </svg>
            <div>No strategies found for the selected filters.</div>
            <div className={s.emptyHint}>
              Try adjusting your filters or time period.
            </div>
          </div>
        )}
      </GlassPanel>
      <RegulatoryDisclaimer compact />

      {/* ── Active Tournaments ─────────────────────────────────────── */}
      {Array.isArray(tournaments) && tournaments.length > 0 && (
        <GlassPanel style={{ marginTop: 20, padding: 18 }}>
          <div style={{ fontSize: 15, fontWeight: 700, color: T.text, marginBottom: 12, display: 'flex', alignItems: 'center', gap: 8 }}>
            <svg width={16} height={16} viewBox="0 0 24 24" fill="none" stroke={T.amber} strokeWidth={2}>
              <path d="M6 9H4.5a2.5 2.5 0 010-5H6M18 9h1.5a2.5 2.5 0 000-5H18M4 22h16M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20 7 22M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20 17 22M18 2H6v7a6 6 0 0012 0V2z" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
            Active Tournaments
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: 12 }}>
            {tournaments.slice(0, 6).map((t, i) => (
              <div key={t.id || i} style={{
                padding: '14px 16px', borderRadius: 10,
                background: '#161B22', border: '1px solid #30363D',
              }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: T.text, marginBottom: 6 }}>
                  {t.name || t.title || `Tournament #${i + 1}`}
                </div>
                <div style={{ fontSize: 11, color: T.textSec, marginBottom: 8 }}>
                  {t.description || t.type || 'Strategy competition'}
                </div>
                <div style={{ display: 'flex', gap: 12, fontSize: 11 }}>
                  <span style={{ color: T.green }}>
                    {t.participants || t.entries || 0} participants
                  </span>
                  <span style={{ color: T.amber }}>
                    {t.prize || t.reward || 'Ranking points'}
                  </span>
                  <span style={{ color: T.textSec }}>
                    {t.status || (t.end_date && new Date(t.end_date) > new Date() ? 'Active' : 'Ended')}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </GlassPanel>
      )}

      </>}

      {/* Share My Rank — Performance Card Modal */}
      {showShare && myCard && <ShareCard card={myCard} onClose={() => setShowShare(false)} />}
    </div>
  );
}
